@strawberry.type
class Seller:
    id: int
    name: str
    price: int
    currency: str


@strawberry.type
class Category:
    id: int
    name: str


@strawberry.type
class Image:
    id: int
    url: str
    alt_text: Optional[str]


@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]

    @strawberry.field
    def reviews(self, info) -> List[Review]:
        return [
            Review(
                id=r.id,
                author=r.author,
                rating=r.rating,
                comment=r.comment,
                created_at=r.created_at,
            )
            for r in self._model.reviews
        ]

    @strawberry.field
    def sellers(self, info) -> List[Seller]:
        return [
            Seller(
                id=s.id,
                name=s.name,
                price=s.price,
                currency=s.currency,
            )
            for s in self._model.sellers
        ]

    @strawberry.field
    def categories(self, info) -> List[Category]:
        return [Category(id=c.id, name=c.name) for c in self._model.categories]

    @strawberry.field
    def images(self, info) -> List[Image]:
        return [Image(id=i.id, url=i.url, alt_text=i.alt_text) for i in self._model.images]

    def __init__(self, model: ProductModel):
        self._model = model
        self.id = model.id
        self.name = model.name
        self.description = model.description


@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> Optional[Product]:
        db: Session = next(get_db())
        try:
            stmt = (
                select(ProductModel)
                .options(
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.sellers),
                    selectinload(ProductModel.categories),
                    selectinload(ProductModel.images),
                )
                .where(ProductModel.id == id)
            )
            model = db.execute(stmt).scalar_one_or_none()
            return Product(model) if model else None
        finally:
            db.close()

    @strawberry.field
    def products(self, info) -> List[Product]:
        db: Session = next(get_db())
        try:
            stmt = select(ProductModel).options(
                selectinload(ProductModel.reviews),
                selectinload(ProductModel.sellers),
                selectinload(ProductModel.categories),
                selectinload(ProductModel.images),
            )
            models = db.execute(stmt).scalars().all()
            return [Product(m) for m in models]
        finally:
            db.close()


schema = strawberry.Schema(query=Query)

